+package valueshape
+
+import "testing"
+
+func TestIPv4OctetBoundary(t *testing.T) {
+	cases := []struct {
+		in   string
+		want Shape
+	}{
+		{"255.255.255.0", ShapeIPv4},
+		{"192.168.1.255", ShapeIPv4},
+		{"255.255.255.255", ShapeIPv4},
+		{"256.1.1.1", ShapeString},
+		{"1.2.3", ShapeString},
+		{"1.2.3.", ShapeString},
+		{"a.b.c.d", ShapeString},
+	}
+	for _, c := range cases {
+		if got := Classify(c.in); got != c.want {
+			t.Errorf("Classify(%q) = %v, want %v", c.in, got, c.want)
+		}
+	}
+}
